#include<bits/stdc++.h>
using namespace std;
map<int,string> ma;
int main(void){
	string str,Name;int n,ans_max=0,sum;
	std::cin>>n;
	for(int i=0;i<n;i++){
		std::cin>>Name>>str;
		sum=0;
		for(int j=0;j+2<=str.size();j++){
			if(str[j]=='s'&&str[j+1]=='o'&&str[j+2]=='s')sum+=1;
		}
		ma[sum]+=Name+' ';
		if(sum>ans_max)ans_max=sum;	
	}
	std::cout<<ma[ans_max]<<endl<<ans_max;
	return false;
}
